  stimulus_type = NULL,
  options = '[{"id":"A","text":"Angelou''s first volume of poetry was \"And Still I Rise.\"","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"Angelou published several works throughout the 1970s and 1980s.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"Angelou''s work explores themes of resilience, hope, and the African American experience.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"Angelou achieved success as a writer after working as a journalist for several years.","is_correct":true,"explanation":"Choice D matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'D',
  explanation = 'The passage primarily focuses on Angelou''s journey to becoming a successful writer, highlighting her transition from journalism to poetry and her eventual recognition as an iconic figure in American literature. The other choices are details that support this main idea. The passage states that "In 1971, after working as a journalist for several years, the writer Maya Angelou published her first volume of poetry, …", which is the textual anchor for eliminating weaker choices. Choice D is correct because it aligns with that evidence: Angelou achieved success as a writer after working as a journalist for several years.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"CID","domain_id":"information","opensat_index":904,"opensat_domain":"Information and Ideas","opensat_raw_id":"random_id_e6","opensat_difficulty":"Hard","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.898Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
